VALUES
  ('aboriginal-c5fb3965-moex-00248', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '下列期望語之使用，錯誤的是：', '["「請鑒核」是指請受文者核定，多使用在下行文", "「請照辦」是請受文者依文照辦，多使用在下行文", "「希辦理見復」是請受文者辦妥後回復，多使用在下行文", "「請備查」是在決定某項事情之後，行文向受文者報備，多使用在上行文"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00249', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「公文用語」中的「臺端」，下列選項敘述正確的是：', '["臺北市長發函給高雄市長時的稱謂語", "信義區公所發文給轄區民眾時的稱謂語", "國立臺灣大學對教育部行文時的稱謂語", "臺北市松山區公所對臺北市政府復文時的稱謂語"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00250', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '公文中關於副本使用之注意事項，下列選項何者正確？', '["如正本附送附件，副本須比照辦理", "副本如附送附件，無須再額外作任何說明", "凡接到副本，為表示明確態度，皆須回覆原單位", "若情況緊急，需越級行文時，得以副本抄送其直屬上級機關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00251', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '關於戶籍登記之申請程序，下列敘述何者錯誤？', '["應由法定之申請人親自申請，不得委託他人為之", "登記之申請，由申請人以書面、言詞或網路向戶政事務所為之", "以言詞為申請時，戶政事務所應代填申請書。必要時，應向申請人朗讀後，由其簽名或蓋章", "除法律另有規定外，結婚登記，以雙方當事人為申請人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "4872a7c22515", "answer_pdf_sha1": "42cd6b1843cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00252', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '甲、乙、丙為同一戶籍，甲為戶長，將戶口名簿交由乙保管，而丙辦理戶籍登記有使用該戶戶口名簿之必 要，下列敘述何者錯誤？', '["戶口名簿應由戶長甲保管", "戶長甲有提供戶口名簿予丙之義務", "戶長甲得於例外情形扣留戶口名簿，則丙應攜帶國民身分證辦理戶籍登記", "若甲未依規定提供戶口名簿時，則可對甲處以新臺幣1,000元以上，3,000元以下罰鍰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "4872a7c22515", "answer_pdf_sha1": "42cd6b1843cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
